import{c as o,Q as s,j as a,m as e}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"Git 总览与心智","description":"","frontmatter":{},"headers":[],"relativePath":"../gitLearning/01-Git总览与心智.md","filePath":"../gitLearning/01-Git总览与心智.md","lastUpdated":1778496697000}'),n={name:"../gitLearning/01-Git总览与心智.md"};function i(r,t,d,l,g,c){return s(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="git-总览与心智" tabindex="-1">Git 总览与心智 <a class="header-anchor" href="#git-总览与心智" aria-label="Permalink to &quot;Git 总览与心智&quot;">​</a></h1><p>学 git 的最大障碍不是&quot;命令记不住&quot;,是<strong>心智模型没建起来</strong>。一个用了五年 git 的人,如果还把它当&quot;带历史的网盘&quot;,那遇到 rebase / cherry-pick / detached HEAD 就会瞬间懵。这一篇不教命令,只讲一件事:<strong>git 到底是什么</strong>。建对模型,后面 21 篇都是顺水推舟;模型错了,记再多命令也是临时记忆。</p><blockquote><p>一句话先记住:<strong>git 是一棵 commit 组成的有向无环图(DAG),分支只是指向某个 commit 的指针</strong>。这一句听上去很学院派,但 git 95% 的&quot;反直觉行为&quot;都源于这个事实——<code>reset</code> 不删 commit、rebase 重写历史、reflog 永远救得回、HEAD 可以 detached……都因为这是图,不是文件夹。</p></blockquote><hr><h2 id="一、git-不是-svn-不是网盘" tabindex="-1">一、git 不是 SVN,不是网盘 <a class="header-anchor" href="#一、git-不是-svn-不是网盘" aria-label="Permalink to &quot;一、git 不是 SVN,不是网盘&quot;">​</a></h2><p>很多人对 git 的初始印象是&quot;高级一点的 SVN&quot;,这个印象会让你<strong>永远学不会 git</strong>。</p><table tabindex="0"><thead><tr><th>维度</th><th>SVN(集中式)</th><th>Git(分布式)</th></tr></thead><tbody><tr><td>历史存哪</td><td>中央服务器</td><td><strong>每台机器都有完整历史</strong></td></tr><tr><td>离线工作</td><td>不能 commit</td><td>全部能干,只 push 时联网</td></tr><tr><td>分支</td><td>路径,新建很贵</td><td><strong>指针,新建几乎免费</strong></td></tr><tr><td>合并</td><td>中心化串行</td><td>DAG,任意两点可合</td></tr><tr><td>心智</td><td>&quot;目录树 + 版本号&quot;</td><td><strong>&quot;提交图 + 引用&quot;</strong></td></tr></tbody></table><p><strong>最要命的差别</strong>:SVN 的版本号是 1, 2, 3, 4 这种全局递增数字,而 git 没有&quot;版本号&quot;,有的是 commit 的 SHA-1 哈希(<code>a3f5b2c...</code>)。这不是设计风格的差异,这是<strong>整个数据模型的差异</strong>——git 没有&quot;线性历史&quot;这个概念,它只有&quot;图&quot;。</p><blockquote><p>如果你脑子里 git 的心智还是&quot;主分支是一条直线,大家往上加&quot;,那你 80% 的协作冲突会想不通。<strong>真正的 git 是一张随时分叉、随时合并的图</strong>,主分支只是图上一条特别长的路径而已。</p></blockquote><hr><h2 id="二、git-的核心数据模型-四种对象" tabindex="-1">二、git 的核心数据模型:四种对象 <a class="header-anchor" href="#二、git-的核心数据模型-四种对象" aria-label="Permalink to &quot;二、git 的核心数据模型:四种对象&quot;">​</a></h2><p>git 底层只有四种对象,理解了这四种,git 命令背后干的事都看得见。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>blob    →  文件内容(只存内容,不存文件名)</span></span>
<span class="line"><span>tree    →  目录(包含一组 blob + 子 tree + 文件名)</span></span>
<span class="line"><span>commit  →  快照 + parent 指针 + 作者 + 时间 + 信息</span></span>
<span class="line"><span>tag     →  指向某个 commit 的&quot;带名字的引用&quot;(annotated tag)</span></span></code></pre></div><p>每个对象都用<strong>自身内容的 SHA-1 哈希</strong>作为唯一 ID。这个设计有几个直接后果:</p><ol><li><strong>任何人在任何机器上算同一段内容,得到的哈希一定相同</strong>——所以 git 可以无中心同步</li><li><strong>改动任何一个 commit,它的哈希就变了,它后面所有 commit 哈希也都变</strong>——所以 rebase 会&quot;重写&quot;</li><li><strong>只要哈希在硬盘上,对象就还在</strong>——所以 reflog / fsck 能救回看似删掉的东西</li></ol><blockquote><p>这就是为什么 git 哈希看起来又长又丑(<code>a3f5b2c4d8e9...</code>)——它不是版本号,它是<strong>内容的指纹</strong>。SVN 的 r123 是人编的,git 的 a3f5b2c 是数学算出来的,<strong>不可能撞、不可能假</strong>。</p></blockquote><hr><h2 id="三、commit-不是-diff-是快照" tabindex="-1">三、commit 不是 diff,是快照 <a class="header-anchor" href="#三、commit-不是-diff-是快照" aria-label="Permalink to &quot;三、commit 不是 diff,是快照&quot;">​</a></h2><p>最普遍的误解:&quot;git commit 存的是这次改了什么&quot;。<strong>错</strong>。git commit 存的是<strong>这次提交时整个项目的快照</strong>——一个 tree 对象,指向所有文件当时的内容。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>commit a3f5b2c</span></span>
<span class="line"><span>├── tree   →  整个项目此刻的目录树</span></span>
<span class="line"><span>├── parent →  上一次 commit 的哈希(可能多个,merge commit)</span></span>
<span class="line"><span>├── author / committer / date</span></span>
<span class="line"><span>└── message</span></span></code></pre></div><p>那 diff 怎么来的?<strong>git 现算的</strong>——拿当前 commit 的 tree,跟 parent 的 tree,递归比 blob 哈希,不一样的就是 diff。这个设计听起来&quot;浪费空间&quot;,但配合 git 的 packfile 压缩,实际上比 SVN 的 diff 链快得多——<strong>因为读取任何一个版本都是 O(1),不用顺着 diff 一路重放</strong>。</p><table tabindex="0"><thead><tr><th>维度</th><th>&quot;存 diff&quot;模型(SVN)</th><th>&quot;存快照&quot;模型(Git)</th></tr></thead><tbody><tr><td>读历史版本</td><td>从最近版本反推 diff,慢</td><td>直接读 tree,O(1)</td></tr><tr><td>占用空间</td><td>看上去小</td><td>靠压缩,实际更小</td></tr><tr><td>心智</td><td>&quot;时间线 + 增量&quot;</td><td>&quot;森林 + 指针&quot;</td></tr></tbody></table><p><strong>这件事还推出一个关键事实</strong>:git 的 commit 是<strong>不可变的</strong>。改了就是新 commit、新哈希。所谓&quot;修改 commit&quot;(<code>commit --amend</code>)其实是<strong>生成一个新 commit 替换掉旧指针</strong>——旧 commit 还躺在硬盘上,所以才有 reflog 能救。</p><hr><h2 id="四、分支与-head-指针-不是文件夹" tabindex="-1">四、分支与 HEAD:指针,不是文件夹 <a class="header-anchor" href="#四、分支与-head-指针-不是文件夹" aria-label="Permalink to &quot;四、分支与 HEAD:指针,不是文件夹&quot;">​</a></h2><p>到这里就可以理解 git 最简洁也最强大的设计:<strong>分支是指向某个 commit 的可变指针</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>            ┌──── main ────┐</span></span>
<span class="line"><span>            ↓               ↓</span></span>
<span class="line"><span>A ──→ B ──→ C ──→ D ──→ E ──→ F</span></span>
<span class="line"><span>                     ↑</span></span>
<span class="line"><span>                   feature</span></span>
<span class="line"><span></span></span>
<span class="line"><span>HEAD → main(我现在在 main 分支)</span></span></code></pre></div><ul><li><code>main</code>、<code>feature</code>、<code>bugfix-x</code> 都是文件,内容就一行,是某个 commit 的哈希</li><li><code>HEAD</code> 也是个文件,内容是 &quot;我现在在哪个分支&quot;(或&quot;detached 在哪个 commit&quot;)</li><li><code>git checkout feature</code> 干的事:把 HEAD 改成指向 feature,工作区内容刷成 feature 指向的 commit</li></ul><p>这件事的副作用极其优雅:</p><ul><li><strong>新建分支 = 写一个 41 字节的文件</strong>,所以分支随便建,不像 SVN 要复制整个目录</li><li><strong>删分支 = 删那个文件</strong>,commit 本身一个不少地留着</li><li><strong>切分支 = 改 HEAD + 刷工作区</strong>,毫秒级</li></ul><blockquote><p>永远记住:<strong>分支不&quot;包含&quot; commit,分支&quot;指向&quot; commit</strong>。一个 commit 可以同时被多个分支指向(merge / 多分支共享祖先);一个 commit 也可以不被任何分支指向(reflog 才找得到)。</p></blockquote><hr><h2 id="五、git-三层工作区-working-staging-repo" tabindex="-1">五、git 三层工作区:working / staging / repo <a class="header-anchor" href="#五、git-三层工作区-working-staging-repo" aria-label="Permalink to &quot;五、git 三层工作区:working / staging / repo&quot;">​</a></h2><p>git 的另一个反直觉设计:文件改动经过<strong>三层</strong>才进入历史。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>工作区 (working dir)</span></span>
<span class="line"><span>       ↓ git add</span></span>
<span class="line"><span>暂存区 (staging / index)</span></span>
<span class="line"><span>       ↓ git commit</span></span>
<span class="line"><span>仓库   (repo / .git)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>区</th><th>是什么</th><th>你操作的命令</th></tr></thead><tbody><tr><td>工作区</td><td>你眼睛看到的目录</td><td>直接 vim / IDE 改</td></tr><tr><td>暂存区</td><td>&quot;下次 commit 要进去什么&quot;的清单</td><td><code>git add</code> / <code>git rm</code></td></tr><tr><td>仓库</td><td>已经永久记录的历史</td><td><code>git commit</code> / <code>git reset</code></td></tr></tbody></table><p><strong>为什么要 staging?</strong> SVN 没有这一层,改了直接 commit。git 加这一层是因为:<strong>真实工作里你一次会同时改 5 个文件,但只想把其中 3 个打成一个有意义的 commit</strong>。staging 让你<strong>精挑细选哪些改动凑成一个原子提交</strong>——这是 git 工程师文化的核心:<strong>commit 应该是有逻辑边界的小单元,不是&quot;工作了一下午&quot;的乱炖</strong>。</p><blockquote><p>没用过 <code>git add -p</code>(交互式逐块 add)的人,等于没用过 git 的精细 commit 能力。这一招后面 04 篇会专门讲。</p></blockquote><hr><h2 id="六、为什么-rebase-cherry-pick-reflog-都不神秘" tabindex="-1">六、为什么 rebase / cherry-pick / reflog 都不神秘 <a class="header-anchor" href="#六、为什么-rebase-cherry-pick-reflog-都不神秘" aria-label="Permalink to &quot;六、为什么 rebase / cherry-pick / reflog 都不神秘&quot;">​</a></h2><p>把上面五件事串起来,git 那些&quot;高级&quot;操作都自然了:</p><table tabindex="0"><thead><tr><th>操作</th><th>实际干了什么</th></tr></thead><tbody><tr><td><code>git merge</code></td><td>把两个 commit 合并成一个新 commit(两个 parent)</td></tr><tr><td><code>git rebase</code></td><td>把一串 commit <strong>重新写一遍</strong>,基于另一个 commit 当 parent。新 commit 哈希全变,旧的留在 reflog</td></tr><tr><td><code>git cherry-pick X</code></td><td>拿 X 这个 commit 的 diff,在当前分支上<strong>重新做一遍</strong>,生成新 commit</td></tr><tr><td><code>git reset --hard X</code></td><td>把当前分支指针挪到 X,工作区刷成 X 的快照。<strong>老 commit 哈希还在,只是没指针了</strong></td></tr><tr><td><code>git revert X</code></td><td><strong>新建一个反向 commit</strong>,效果是抵消 X(不动历史)</td></tr><tr><td><code>git reflog</code></td><td>显示所有 HEAD / 分支指针的移动记录,即使 commit 没分支指了也能找到</td></tr></tbody></table><blockquote><p>一旦你看清&quot;分支是指针、commit 是不可变快照、reflog 记录所有指针动作&quot;,git 就再没有黑魔法了。<strong>rebase 不是危险——它是&quot;重写一段历史的清晰命令&quot;;<code>reset --hard</code> 不会丢数据——只要哈希还在 reflog 里就找得回</strong>。</p></blockquote><hr><h2 id="七、用-git-的两种心态" tabindex="-1">七、用 git 的两种心态 <a class="header-anchor" href="#七、用-git-的两种心态" aria-label="Permalink to &quot;七、用 git 的两种心态&quot;">​</a></h2><p>学 git 的人有两种,两种人差别不在命令熟练度,在<strong>心态</strong>:</p><p><strong>A. &quot;git 是危险的,我别动太多&quot;</strong></p><ul><li>只用 add / commit / push / pull</li><li>不敢 rebase,怕&quot;丢提交&quot;</li><li>出事了第一反应是删仓库重 clone</li><li>永远学不会 git</li></ul><p><strong>B. &quot;git 是图操作工具,我能精确控制每一步&quot;</strong></p><ul><li>rebase / cherry-pick 当家常便饭</li><li>出事了先 <code>git reflog</code></li><li>能写出干净的 commit 历史让别人 review 时省时间</li><li>半年后能给别人解释 detached HEAD</li></ul><blockquote><p>转变的关键是<strong>信任 reflog</strong>。reflog 默认保留 90 天,意味着<strong>90 天内你做的任何操作都能撤销</strong>。一旦相信这件事,你就敢动 git 了——动得越多,熟得越快。</p></blockquote><hr><h2 id="八、本系列的整体地图" tabindex="-1">八、本系列的整体地图 <a class="header-anchor" href="#八、本系列的整体地图" aria-label="Permalink to &quot;八、本系列的整体地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01     总览(这篇)</span></span>
<span class="line"><span>02-05  基础:配置 → 三层模型 → add/commit → log</span></span>
<span class="line"><span>       这一段是&quot;会用 git&quot; 的全部,优先级最高</span></span>
<span class="line"><span></span></span>
<span class="line"><span>06-10  分支与协作:branch / merge / rebase / push / tag</span></span>
<span class="line"><span>       这一段是&quot;和别人 git&quot; 的核心,缺一不可</span></span>
<span class="line"><span></span></span>
<span class="line"><span>11-15  应急与整理:stash / cherry-pick / reset / reflog / gitignore</span></span>
<span class="line"><span>       这一段是&quot;出事时救命&quot;,每篇对应一个真实事故场景</span></span>
<span class="line"><span></span></span>
<span class="line"><span>16-22  工程化:submodule / hooks / worktree / 工作流 / 大仓库 / 安全</span></span>
<span class="line"><span>       这一段是&quot;团队 / 大项目&quot;层面,按需看</span></span></code></pre></div><p><strong>优先级</strong>:01-10 每篇都建议看;11-15 按需,但 14 reflog 强烈推荐;16 之后看团队规模。</p><hr><h2 id="九、踩坑提醒-总览版-后面每篇细讲" tabindex="-1">九、踩坑提醒(总览版,后面每篇细讲) <a class="header-anchor" href="#九、踩坑提醒-总览版-后面每篇细讲" aria-label="Permalink to &quot;九、踩坑提醒(总览版,后面每篇细讲)&quot;">​</a></h2><ol><li><strong>把 git 当 SVN 用</strong>——只用 commit / push / pull,永远摸不到 git 真正的好</li><li><strong>怕 rebase</strong>——rebase 不会丢东西,丢东西的是不会用 reflog 的人</li><li><strong>不读 git status</strong>——很多事故源于&quot;我以为现在干净了,其实还有未 commit 的改动&quot;</li><li><strong>commit message 写 &quot;fix&quot;</strong> ——一个月后你和同事都看不懂这是修了什么</li><li><strong>不分支直接在 main 上工作</strong>——团队协作大忌,审 PR / rebase / 回滚都做不了</li><li><strong>乱用 <code>git push --force</code></strong>——强推到共享分支会把别人的提交覆盖,<strong><code>--force-with-lease</code> 永远比 <code>--force</code> 安全</strong></li><li><strong>不知道 reflog</strong>——上面说过,就是这一招让 git 成为&quot;敢动的工具&quot;</li><li><strong>submodule 用一次哭三天</strong>——除非真的需要,否则别上 submodule(详见 16 篇)</li><li><strong>不写 .gitignore</strong>——node_modules / .env / dist 进了 git 之后清不掉,污染历史</li><li><strong>认为合并冲突很神秘</strong>——其实就是两个改动碰一起了,看 diff 就懂(详见 07 篇)</li></ol><hr><p>下一篇:<code>02-安装配置与三层config.md</code>,讲 git config 的 system / global / local 三层、<code>.gitconfig</code> 怎么写最有用的别名、为什么有人改 commit 一直显示成别人。</p>`,60)])])}const m=o(n,[["render",i]]);export{u as __pageData,m as default};
